// ============================================================
// LogService v2 — Validation + Génération log_id (BATCH)
// ============================================================
// CHANGEMENTS vs v1 :
//   - Supporte le batch (multiple items en entrée)
//   - Prépare la requête SQL paramétrisée
//   - Suppression de la dépendance au format Airtable
// ============================================================

const items = $input.all();

const VALID_AGENTS = [
  'ORCHESTRATOR',
  'INGESTION_AGENT',
  'ADAPTATION_AGENT',
  'PUBLICATION_AGENT',
  'NOTIFICATION_AGENT',
  'SYSTEM'
];

return items.map((it, idx) => {
  const input = it.json || {};

  // --- Extraction ---
  let agent = input.agent;
  const event_type = input.event_type;
  let message = input.message;
  const job_id = input.job_id || null;
  const correlation_id = input.correlation_id || null;
  const tenant_id = input.tenant_id || 1;

  // --- Validation structurelle ---
  const missing = [];
  if (!agent) missing.push('agent');
  if (!event_type) missing.push('event_type');

  if (missing.length > 0) {
    throw new Error(
      `LogService — Item[${idx}] Champs critiques manquants: ${missing.join(', ')}`
    );
  }

  // --- Message défensif ---
  if (!message || message.toString().trim() === '') {
    message = `ALERTE : Événement logué sans message fourni (Type: ${event_type})`;
  }

  // --- Agent inconnu → fallback SYSTEM ---
  if (!VALID_AGENTS.includes(agent)) {
    message = `AGENT INCONNU DÉTECTÉ (${agent}) — Message original: ${message}`;
    agent = 'SYSTEM';
  }

  // --- Génération log_id ---
  const now = new Date();
  const y = now.getFullYear();
  const m = String(now.getMonth() + 1).padStart(2, '0');
  const d = String(now.getDate()).padStart(2, '0');
  const hex = Array.from({ length: 6 }, () =>
    Math.floor(Math.random() * 16).toString(16).toUpperCase()
  ).join('');
  const log_id = `LOG-${y}${m}${d}-${hex}`;

  // --- Timestamp ISO 8601 ---
  const timestamp = now.toISOString();

  return {
    json: {
      ...input,
      log_id,
      job_id,
      correlation_id,
      agent,
      event_type,
      message,
      tenant_id,
      timestamp
    },
    pairedItem: { item: idx },
  };
});

