INSERT INTO diffusion.log_events (log_id, job_id, correlation_id, agent, event_type, message, tenant_id, timestamp)
VALUES ($1, $2, $3, $4, $5, $6, $7::bigint, $8::timestamptz)
RETURNING id, log_id, timestamp;

