// ============================================================
// LogService v2 — Construire la réponse (PostgreSQL)
// ============================================================
// CHANGEMENTS vs v1 :
//   - Remplace airtable_record_id par db_id (BIGSERIAL PG)
//   - Gestion d'erreur gracieuse (le log ne doit JAMAIS
//     bloquer le workflow appelant)
//   - Supporte le batch
// ============================================================

const items = $input.all();
const validatedItems = $items('Valider & Générer log_id');

return items.map((it, idx) => {
  const pgResult = it.json;
  const validated = validatedItems[idx]?.json || {};

  // Si PostgreSQL a retourné une erreur
  if (pgResult.error || (!pgResult.id && !pgResult.log_id)) {
    return {
      json: {
        ...validated,
        db_id: null,
        success: false,
        error_message: pgResult.error || 'INSERT échoué — cause inconnue',
      },
      pairedItem: { item: idx },
    };
  }

  return {
    json: {
      ...validated,
      log_id: pgResult.log_id || validated.log_id,
      timestamp: pgResult.timestamp || validated.timestamp,
      db_id: pgResult.id || null,
      success: true,
    },
    pairedItem: { item: idx },
  };
});
